import{_ as e,o as t,c as o,a3 as n}from"./chunks/framework.CVjg771q.js";const _=JSON.parse('{"title":"生肖 · 羊","description":"未羊——温驯善良，知恩图报","frontmatter":{"pageClass":"dao-changshi-page","aside":false,"title":"生肖 · 羊","description":"未羊——温驯善良，知恩图报"},"headers":[],"relativePath":"changshi/shengxiao/yang.md","filePath":"changshi/shengxiao/yang.md","lastUpdated":1779783531000}'),s={name:"changshi/shengxiao/yang.md"};function r(i,a,p,c,h,l){return t(),o("div",null,[...a[0]||(a[0]=[n('<h1 id="未羊" tabindex="-1">未羊 <a class="header-anchor" href="#未羊" aria-label="Permalink to &quot;未羊&quot;">​</a></h1><blockquote><p>地支「未」· 未时（13:00–15:00）· 五行属土 · 阴阳为阴</p></blockquote><p>羊温驯善良，知恩图报，是一种珍贵的「瑞兽」。羊自古以来被赋予了礼仪、君子、公正、感恩等文化属性。先秦时期，著名的青铜器四羊方尊就充分显示了人们对羊的重视。《说文解字》解释「羊」为「祥也」——羊与祥相通。</p><h2 id="生肖故事-神羊盗五谷" tabindex="-1">生肖故事：神羊盗五谷 <a class="header-anchor" href="#生肖故事-神羊盗五谷" aria-label="Permalink to &quot;生肖故事：神羊盗五谷&quot;">​</a></h2><p>上古时期，人间没有五谷杂粮，人们只能用野草野菜充饥，日子过得非常艰难。一年秋天，一只神羊到人间游玩。它向村民借吃的，接连遇见好几个村民都摇摇头走了。后来一个好心人把神羊带回家，给了它一些野菜，无奈地说：「乡亲们自己都没有东西吃，这些野草野果就是我们全部的食物了。」</p><p>神羊这才知道，谷物只是天上的神物，人间根本没有。心软的神羊决定将天上的谷物种子带给人间受苦的百姓。它溜进仓库，拿了稻、稷、麦、豆、麻五种谷物的种子藏在口中，飞到凡间送给百姓，并教会百姓种植方法。人们这才吃上了五谷杂粮。</p><p>玉帝知道后一怒之下把神羊贬下凡间，罚它生生世世以草为食。人们为了感恩神羊的恩赐，在玉帝选拔十二生肖时大力举荐羊，羊就顺利上了十二生肖榜。</p><p><strong>生肖习俗</strong>：山西忻州流行「挠羊赛」——连续摔倒六人的获胜者奖励一只活羊，将羊高举绕场一周向神灵致敬。羊在中国文化中是吉祥的象征，蒙古族新生儿出生时用羊皮包裹，成年时将羊毛线围在脖子上祈求吉祥。</p>',8)])])}const g=e(s,[["render",r]]);export{_ as __pageData,g as default};
